VALUES
  ('social-worker-moex-02586', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '面對人口老化的問題，世界衛生組織（WHO）在2007年提出高齡友善城市的理念及建設，請問此高齡友 善城市的框架乃植基於下列何種概念而成？', '["在地老化", "友善老化", "健康老化", "活躍老化"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02587', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據老人福利法，有關「生活津貼」與「特別照顧津貼」之規定，下列陳述何者正確？', '["生活津貼為普及性給付，凡年滿65歲以上之公民皆有資格領取", "生活津貼的領取資格排除已接受收容安置之老人", "特別照顧津貼為選擇性給付，其家庭必須具備低收入戶身分才有資格領取", "特別照顧津貼限定在失能程度評估為重度、且由家人照顧的老人，該給付由老人領取"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02588', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據兒童及少年福利與權益保障法，下列關於收出養規定的陳述，何者錯誤？', '["從事收出養媒合服務，以經主管機關許可之財團法人、公私立兒童及少年安置、教養機構為限", "收出養媒合服務者從事收出養服務，得向收養人收取費用", "凡父母欲出養兒童及少年，包括親屬之間或繼父母對繼子女間的收出養，均須委託並通過收出養媒合 服務者的評估", "父母對於兒童及少年出養之意見不一致時，父母之一方可以向法院聲請認可"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02589', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據身心障礙者權益保障法，有關身心障礙者之身分鑑定與需求評估，下列陳述何者正確？', '["該法所稱身心障礙者係指身體系統構造或功能，有損傷或不全導致顯著偏離或喪失，影響其活動與參 與社會生活，經醫療專業人員鑑定及評估，領有身心障礙證明者", "身心障礙證明最長期限為3年", "主管機關取得衛生主管機關核轉之身心障礙鑑定報告後，需籌組專業團隊進行需求評估", "各級主管機關與目的事業單位需依服務需求評估之結果，提供身心障礙者無差別性與一致化的服務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02590', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '家庭暴力防治法規定某些人員在執行職務時知有疑似家庭暴力情事者，應在24小時內通報當地主管機關。 請問：下列那一類人員並未被賦予上述的通報責任？', '["學校老師", "里長", "社會工作人員", "保育人員"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02591', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '新修正的社會救助法將「中低收入戶」法制化。請問：中低收入戶的家庭所得標準為家庭總收入除以家 庭總人口，每人每月不超過最低生活費用的多少倍？', '["1.5倍", "2倍", "2.5倍", "3倍"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02592', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據社會工作師法，即便通過社會工作師考試，有特殊情事，主管機關亦不得發給執業執照；已領取者， 撤銷或廢止之。請問：上述之「特殊情事」不包含下列那項陳述？', '["犯有妨害性自主罪，經有罪判決確定", "受監護或輔助宣告，尚未撤銷", "罹患精神疾病，經主管機關委請相關專科醫師認定不能執行業務", "因出境歇業，未報請主管機關備查"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02593', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據社會工作師法，直轄市或縣（市）社會工作師達多少人以上，可以成立該區域之社會工作師公會？', '["10人", "15人", "20人", "25人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02594', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據特殊境遇家庭扶助條例，申請緊急生活扶助金之特殊境遇家庭，原則上每人每次領取補助之期限為 多久？', '["1個月", "3個月", "6個月", "1年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02595', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '性侵害犯罪防治法設有「陪同偵訊」之規定，請問：下列那一類人員並未被允許陪同性侵害被害人偵訊？', '["被害人之親阿姨", "被害人之男朋友", "社工", "醫師"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02596', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據性別工作平等法，有關「育嬰留職停薪」之規定，下列那一項陳述正確？', '["凡受僱者任職滿1年後，於每一子女滿2歲前，得申請育嬰留職停薪", "育嬰留職停薪期間，每一子女不得逾3年", "同時撫育2名子女以上者，其育嬰留職停薪期間應分開計算", "受僱者於育嬰留職停薪期間，得繼續參加原有之社會保險，原由雇主繳納之保費免予繳納"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02597', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據全民健康保險法，被保險人區分成六大類。請問：符合社會救助法規定之低收入戶成員為第幾類被 保險人？', '["第三類", "第四類", "第五類", "第六類"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02598', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依照國民年金法第32條之1規定，被保險人分娩或早產，得請領生育給付，其給付標準如下列，請問何 者錯誤？', '["分娩者，按其月投保金額一次發給1個月生育給付", "早產者，按其月投保金額一次發給3個月生育給付", "分娩或早產為雙生以上者，比例增給", "被保險人同時符合相關社會保險生育給付或補助條件者，僅得擇一請領"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02599', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於身心障礙者遭受遺棄、虐待、限制其自由等各種行為且情況危急非立即給予保護、安置或其他處置， 其生命、身體或自由有立即之危險或有危險之虞者，依身心障礙者權益保障法第80條所示，身心障礙者 之緊急保護安置，不得超過72小時，而非72小時以上之安置，不足以保護身心障礙者時，得聲請法院 裁定繼續保護安置，期限是以多久為限？', '["1個月", "3個月", "6個月", "9個月"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02600', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '就兒童及少年性交易防制條例第18條所示，經法院依審理之結果，認為兒童或少年從事性交易者，法院 應裁定將其安置於中途學校，並施予多少年之特殊教育？', '["1年", "2年", "3年", "4年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02601', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依兒童及少年福利與權益保障法第64條所示，關於目睹家庭暴力之兒童及少年，經直轄市、縣（市）主 管機關列為保護個案者，該主管機關應於多久時間內提出兒童及少年家庭處遇計畫？', '["1個月", "2個月", "3個月", "6個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02602', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '對於經鑑別為人口販運被害人，且無合法有效之停（居）留許可者，中央主管機關應核發幾個月以下效 期之臨時停留許可？', '["3個月", "5個月", "6個月", "9個月"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02603', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '依性別工作平等法第17條，受僱者於育嬰留職停薪期滿後，申請復職時，除有下列情形之一，並經主管 機關同意者外，雇主不得拒絕。所稱「下列情形」何者錯誤？', '["歇業、虧損或業務緊縮者", "雇主依法變更組織、解散或轉讓者", "不可抗力暫停工作在3個月以上者", "業務性質變更，有減少受僱者之必要，又無適當工作可供安置者"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02604', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '根據原住民族工作權保障法第12條，依政府採購法得標之廠商，於國內員工總人數逾100人者，應於履 約期間僱用原住民，其人數不得低於總人數的多少百分比？', '["百分之一", "百分之三", "百分之五", "百分之七"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02605', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '下列有關老年農民福利津貼暫行條例的條文內容，何者錯誤？', '["本條例所稱老年農民指年滿65歲國民，在國內設有戶籍，且於最近3年內每年居住超過183日者", "申領時參加農民健康保險之農民且加保年資合計15年以上者", "符合資格者得申請發給福利津貼，每月新臺幣7000元，發放至本人死亡當月", "福利津貼每3年調整1次，由中央主關機關參照中央主計機關發布之最近1年消費者物價指數較前次 調整之前1年消費者物價指數成長率公告調整之"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02606', 'social-worker', 'social-worker-moex-104-d2552697', 'sub-social-worker-06', NULL, 'single_choice', '社會保險雖以保障經濟安全為主要目的，但不完全是現金給付，採服務給付亦不少見。請問：下列那一 項社會保險中的給付形式係以「服務」為主？', '["勞工保險條例之失能給付", "國民年金法之生育給付", "全民健康保險法之醫療給付", "就業保險法之育兒留職停薪津貼"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "61d6764899ef", "answer_pdf_sha1": "8f599724e6cb", "source_family": "moex-gov-tw", "moex": {"exam_code": "104030", "c": "110", "s": "0604", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "社會政策與社會立法", "year": "104", "exam_name": "104年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02607', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於近年之家庭變遷的趨勢，下列敘述何者錯誤？', '["和以往相較，選擇單身的成人越來越多", "進入婚姻關係後的成人，越來越多夫妻選擇不生小孩", "因應照顧孩子的需要，有越來越多的婦女選擇放棄工作", "因為壽命延長，可能因為沒有兒女或兒女忙於工作不在身邊，使得越來越多的銀髮族夫妻相依為命"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02608', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '根據單親家庭狀況調查，下列那一項陳述不符合臺灣的單親家庭狀況？', '["形成單親家庭的原因以離婚為主因", "最困擾的議題為就業及經濟問題", "女性單親家庭多於男性單親家庭", "女性單親家庭的子女多於男性單親家庭"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02609', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於各項發展階段理論的敘述，下列何者錯誤？', '["「心理動力論」指出各發展階段慾望過度滿足或不滿足，個體都會產生固著而無法進入下一階段", "「心理社會發展論」指出無論現階段的任務、衝突能否解決，個體都會進入下一階段，不會再面對前 面階段的課題", "「認知發展論」指出個體在不同發展階段會因為心理結構不同而有不同認知歷程，說明兒童與成人的 心理與認知架構有異", "各發展階段理論皆有其限制或不足，不宜依賴單一理論來評估個人的心理和認知功能"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-02610', 'social-worker', 'social-worker-moex-103-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據衛生福利部的資料顯示，下列那一個年齡層的自殺率最高？', '["15-19歲", "20-24歲", "60-64歲", "65歲以上"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:13+00:00", "source_pdf_sha1": "3dff85772cd2", "answer_pdf_sha1": "ed0fa7b179fa", "source_family": "moex-gov-tw", "moex": {"exam_code": "103030", "c": "110", "s": "0605", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "人類行為與社會環境", "year": "103", "exam_name": "103年第一次專技醫師中醫師分階段考試、中醫師營養師心理師護理師社會工作師考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
